const byCitySlug: Record<string, CostOfLivingProfile> = {};
for (const profile of costOfLivingProfiles) {
  byCitySlug[profile.citySlug] = profile;
}

/** Build-time integrity guard — throws (failing `next build`) on any invalid profile. */
function assertCostOfLivingIntegrity(
  profiles: readonly CostOfLivingProfile[],
): void {
  const errors: string[] = [];
  const seen = new Set<string>();
  for (const p of profiles) {
    if (seen.has(p.citySlug)) errors.push(`duplicate citySlug: ${p.citySlug}`);
    seen.add(p.citySlug);
    const values = [
      p.monthlyCostSingle, p.monthlyCostCouple, p.monthlyCostFamily,
      p.rentStudio, p.rentOneBedroom, p.rentThreeBedroom,
      p.mealRestaurant, p.coffee, p.publicTransportPass,
    ];
    if (values.some((n) => typeof n !== "number" || !Number.isFinite(n) || n <= 0)) {
      errors.push(`${p.citySlug}: non-positive or invalid numeric value`);
    }
    if (!(p.affordabilityScore >= 0 && p.affordabilityScore <= 100)) {
      errors.push(`${p.citySlug}: affordabilityScore out of range`);
    }
    if (!p.localCurrency) errors.push(`${p.citySlug}: missing localCurrency`);
  }
  if (errors.length > 0) {
    throw new Error(`cost-of-living integrity failure:\n${errors.join("\n")}`);
  }
}

assertCostOfLivingIntegrity(costOfLivingProfiles);

export function getCostOfLiving(
  citySlug: string,
): CostOfLivingProfile | undefined {
  return byCitySlug[citySlug];
}

export function hasCostOfLiving(citySlug: string): boolean {
  return Object.prototype.hasOwnProperty.call(byCitySlug, citySlug);
}

export function getAllCostProfiles(): readonly CostOfLivingProfile[] {
  return costOfLivingProfiles;
}
